-- Generated by infa2dbt
{{ config(materialized='view') }}

WITH aar_base_data AS (
  SELECT * FROM {{ ref('int_eqpmnt_aar_base_filtered') }}
),

pool_lookup AS (
  SELECT * FROM {{ ref('int_eqpmnt_pool_lookup') }}
),

dim_equipment_lookup AS (
  SELECT * FROM {{ ref('int_dim_equipment_lookup') }}
)

SELECT
  s.*,
  TRIM(s.EQPUN_NBR) AS o_EQPUN_NBR,
  TRIM(s.MARK_CD) AS O_MARK_CD,

  -- Lookup results
  d.DIM_EQUIPMENT_ID AS o_DIM_EQUIPMENT_ID,
  p.EQPMNT_POOL_ID AS lkp_EQPMNT_POOL_ID,
  p.FLEET_NM AS lkp_FLEET_NM,
  p.FLEET_SBGRP_CTGRY_NM AS lkp_FLEET_SBGRP_CTGRY_NM,
  p.PARTY_NM AS lkp_PARTY_NM,
  p.FLEET_ID AS lkp_FLEET_ID,
  p.TARGET_EQPMT_CTGRY_NM AS lkp_TARGET_EQPMT_CTGRY_NM,
  p.PRDCT_NM AS lkp_PRDCT_NM,

  -- Derived fields (simplified for this example)
  'Y' AS REGISTERED_IND,
  'Y' AS SRC_REGSTRD,
  IFF(d.DIM_EQUIPMENT_ID IS NULL, 'I', 'U') AS I_U_FLG,
  '' AS o_MAX_DIM_EQUIPMENT_ID,

  -- Car ownership logic (simplified)
  CASE
    WHEN s.OWNER_MARK_CD = 'TTX' THEN 'TTX'
    ELSE 'FOREIGN'
  END AS CAR_OWNERSHIP,

  'N' AS LEASED_IND,
  'Y' AS CP_OWNED_IND,
  'N/A' AS AAR_EQPMNT_POOL_ID,
  'N/A' AS CPR_EQPMT_POOL_ID,
  'N/A' AS o_LESSEE_MARK_CD,
  'N/A' AS o_CAR_KIND_CD,
  'N/A' AS o_MARK_OWNER_CTGRY_CD,
  'N/A' AS o_CP_REG_MARK_CD,
  'N/A' AS o_LS_CP_REG_MARK_CD,
  'N/A' AS o_STNC_CP_REG_MARK_CD

FROM aar_base_data s
LEFT JOIN dim_equipment_lookup d
  ON TRIM(s.MARK_CD) = d.MARK_CD
  AND TRIM(s.EQPUN_NBR) = d.EQPUN_NBR
LEFT JOIN pool_lookup p
  ON s.EQPMNT_ID = p.EQPMNT_ID
